const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const action = String(body.action || '').toLowerCase().trim();
const allowed = ['list', 'schedule', 'cancel'];
if (allowed.indexOf(action) === -1) return { json: { ok: false, status: 400, error: 'Unknown action' } };

return { json: {
  token: token,
  action: action,
  avatar_name:        String(body.avatar_name || 'AVA').trim(),
  content_topic_id:   body.content_topic_id || null,
  scheduled_for:      body.scheduled_for    || null,
  intended_platforms: Array.isArray(body.intended_platforms) ? body.intended_platforms : [],
  library_id:         body.library_id || null,
  notes:              (body.notes || '').toString().slice(0, 500) || null,
  status_filter:      body.status_filter || null
} };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract Inputs').item.json;
return { json: Object.assign({ ok: true }, x) };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Query Library');
const byStatus = { queued: [], rendering: [], ready: [], published: [], archived: [], failed: [] };
rows.forEach(function (r) {
  const s = r.status || 'queued';
  if (!byStatus[s]) byStatus[s] = [];
  byStatus[s].push(r);
});
return { json: {
  ok: true,
  rows: rows,
  by_status: byStatus,
  counts: {
    total:     rows.length,
    queued:    byStatus.queued.length,
    rendering: byStatus.rendering.length,
    ready:     byStatus.ready.length,
    published: byStatus.published.length
  }
} };

