    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const avs = allOf('Lookup Avatar');
if (avs.length === 0) return { json: { ok: false, status: 404, error: 'Avatar not found' } };
const x = $('Check Admin').item.json;
if (!x.content_topic_id) return { json: { ok: false, status: 400, error: 'content_topic_id required' } };
if (!x.scheduled_for)    return { json: { ok: false, status: 400, error: 'scheduled_for required (ISO 8601)' } };
return { json: {
  body: {
    avatar_id:          avs[0].id,
    content_topic_id:   x.content_topic_id,
    status:             'queued',
    intended_platforms: x.intended_platforms || [],
    scheduled_for:      x.scheduled_for,
    notes:              x.notes
  }
} };

