const src = ['Insert Library Row', 'Patch Cancel', 'Shape List'].find(function (n) {
  try { return $(n).all().length > 0; } catch (e) { return false; }
});
if (!src) return { json: { ok: false, status: 500, error: 'No action completed' } };
if (src === 'Shape List') return { json: $('Shape List').first().json };
const rows = allOf(src);
if (rows.length === 0) {
  return { json: { ok: false, status: 404, error: 'No row affected by ' + src } };
}
return { json: { ok: true, action: $('Check Admin').item.json.action, row: rows[0] } };
